{
  "name": "Mess Manager - Meal Tracking System",
  "description": "A comprehensive meal and expense management system for mess members to track daily meals, bazaar costs, deposits, and monthly calculations."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Member {
  id: string;
  name: string;
  phone?: string;
  joinDate: string;
}

export interface MealCounts {
  breakfast: number; // usually 0 or 1
  lunch: number;
  dinner: number;
}

export interface DailyEntry {
  date: string; // ISO string YYYY-MM-DD
  bazaarAmount: number;
  bazaarDescription: string;
  meals: Record<string, MealCounts>; // memberId -> counts
}

export interface Deposit {
  id: string;
  memberId: string;
  amount: number;
  date: string;
  note?: string;
}

export interface AppState {
  members: Member[];
  dailyEntries: Record<string, DailyEntry>; // date -> entry
  deposits: Deposit[];
  otherExpenses: number;
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Users, 
  Calendar, 
  Wallet, 
  BarChart3, 
  Settings, 
  Plus, 
  ChevronLeft, 
  ChevronRight,
  TrendingUp,
  ArrowUpRight,
  ArrowDownRight,
  Utensils
} from 'lucide-react';
import { Member, DailyEntry, Deposit, AppState, MealCounts } from './types';
import Dashboard from './components/Dashboard';
import MemberTab from './components/MemberTab';
import EntryTab from './components/EntryTab';
import DepositTab from './components/DepositTab';
import ReportTab from './components/ReportTab';

const STORAGE_KEY = 'mess_manager_v1';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'members' | 'entries' | 'deposits' | 'reports'>('dashboard');
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : {
      members: [],
      dailyEntries: {},
      deposits: [],
      otherExpenses: 0
    };
  });

  // Persist state
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  const updateState = (updater: (prev: AppState) => AppState) => {
    setState(prev => updater(prev));
  };

  const currentMonth = new Date().toISOString().slice(0, 7); // YYYY-MM

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard state={state} onTabChange={setActiveTab} />;
      case 'members':
        return <MemberTab state={state} updateState={updateState} />;
      case 'entries':
        return <EntryTab state={state} updateState={updateState} />;
      case 'deposits':
        return <DepositTab state={state} updateState={updateState} />;
      case 'reports':
        return <ReportTab state={state} updateState={updateState} />;
      default:
        return <Dashboard state={state} onTabChange={setActiveTab} />;
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col md:flex-row">
      {/* Sidebar - Desktop */}
      <nav className="hidden md:flex flex-col w-64 bg-white border-r border-gray-200 h-screen sticky top-0">
        <div className="p-6 border-b border-gray-100 flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white">
            <Utensils size={24} />
          </div>
          <span className="font-bold text-xl tracking-tight text-gray-800">Mess Manager</span>
        </div>

        <div className="flex-1 py-6 space-y-1 px-3">
          <NavButton 
            active={activeTab === 'dashboard'} 
            onClick={() => setActiveTab('dashboard')} 
            icon={<BarChart3 size={20} />} 
            label="Dashboard" 
          />
          <NavButton 
            active={activeTab === 'members'} 
            onClick={() => setActiveTab('members')} 
            icon={<Users size={20} />} 
            label="Members" 
          />
          <NavButton 
            active={activeTab === 'entries'} 
            onClick={() => setActiveTab('entries')} 
            icon={<Calendar size={20} />} 
            label="Daily Entries" 
          />
          <NavButton 
            active={activeTab === 'deposits'} 
            onClick={() => setActiveTab('deposits')} 
            icon={<Wallet size={20} />} 
            label="Deposits" 
          />
          <NavButton 
            active={activeTab === 'reports'} 
            onClick={() => setActiveTab('reports')} 
            icon={<TrendingUp size={20} />} 
            label="Reports" 
          />
        </div>

        <div className="p-4 border-t border-gray-100">
           <div className="bg-indigo-50 rounded-lg p-3 text-sm text-indigo-700 font-medium">
             Active: {state.members.length} Members
           </div>
        </div>
      </nav>

      {/* Mobile Top Bar */}
      <div className="md:hidden flex items-center justify-between p-4 bg-white border-b border-gray-200 sticky top-0 z-50">
        <div className="flex items-center gap-2">
          <Utensils className="text-indigo-600" size={24} />
          <span className="font-bold text-lg">Mess Manager</span>
        </div>
      </div>

      {/* Main Content */}
      <main className="flex-1 p-4 md:p-8 overflow-x-hidden">
        {renderContent()}
      </main>

      {/* Mobile Bottom Nav */}
      <nav className="md:hidden flex justify-around items-center p-3 bg-white border-t border-gray-200 sticky bottom-0 z-50">
        <MobileNavButton 
          active={activeTab === 'dashboard'} 
          onClick={() => setActiveTab('dashboard')} 
          icon={<BarChart3 size={20} />} 
        />
        <MobileNavButton 
          active={activeTab === 'members'} 
          onClick={() => setActiveTab('members')} 
          icon={<Users size={20} />} 
        />
        <MobileNavButton 
          active={activeTab === 'entries'} 
          onClick={() => setActiveTab('entries')} 
          icon={<Calendar size={20} />} 
        />
        <MobileNavButton 
          active={activeTab === 'deposits'} 
          onClick={() => setActiveTab('deposits')} 
          icon={<Wallet size={20} />} 
        />
        <MobileNavButton 
          active={activeTab === 'reports'} 
          onClick={() => setActiveTab('reports')} 
          icon={<TrendingUp size={20} />} 
        />
      </nav>
    </div>
  );
};

const NavButton: React.FC<{ 
  active: boolean; 
  onClick: () => void; 
  icon: React.ReactNode; 
  label: string 
}> = ({ active, onClick, icon, label }) => (
  <button 
    onClick={onClick}
    className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg text-sm font-medium transition-all ${
      active 
        ? 'bg-indigo-50 text-indigo-600 shadow-sm' 
        : 'text-gray-600 hover:bg-gray-50 hover:text-gray-900'
    }`}
  >
    {icon}
    {label}
  </button>
);

const MobileNavButton: React.FC<{ 
  active: boolean; 
  onClick: () => void; 
  icon: React.ReactNode 
}> = ({ active, onClick, icon }) => (
  <button 
    onClick={onClick}
    className={`p-3 rounded-xl transition-all ${
      active ? 'bg-indigo-100 text-indigo-600' : 'text-gray-400'
    }`}
  >
    {icon}
  </button>
);

export default App;

import React, { useMemo } from 'react';
import { AppState } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { ShoppingCart, UtensilsCrossed, PiggyBank, Receipt } from 'lucide-react';

interface Props {
  state: AppState;
  onTabChange: (tab: any) => void;
}

const Dashboard: React.FC<Props> = ({ state, onTabChange }) => {
  const stats = useMemo(() => {
    let totalBazaar = 0;
    let totalMeals = 0;
    Object.values(state.dailyEntries).forEach(entry => {
      totalBazaar += entry.bazaarAmount;
      Object.values(entry.meals).forEach(m => {
        totalMeals += (m.breakfast + m.lunch + m.dinner);
      });
    });

    const totalDeposits = state.deposits.reduce((acc, d) => acc + d.amount, 0);
    const mealRate = totalMeals > 0 ? (totalBazaar + state.otherExpenses) / totalMeals : 0;

    // Daily bazaar chart data (last 7 days)
    const sortedDates = Object.keys(state.dailyEntries).sort();
    const chartData = sortedDates.slice(-7).map(date => ({
      name: date.slice(8), // day only
      amount: state.dailyEntries[date].bazaarAmount
    }));

    return { totalBazaar, totalMeals, totalDeposits, mealRate, chartData };
  }, [state]);

  return (
    <div className="space-y-6">
      <header>
        <h1 className="text-2xl font-bold text-gray-900">Dashboard</h1>
        <p className="text-gray-500">Overview of the current mess status</p>
      </header>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard 
          icon={<ShoppingCart className="text-emerald-600" />} 
          title="Total Bazaar" 
          value={`৳${stats.totalBazaar}`} 
          color="bg-emerald-50"
        />
        <StatCard 
          icon={<UtensilsCrossed className="text-indigo-600" />} 
          title="Total Meals" 
          value={stats.totalMeals.toString()} 
          color="bg-indigo-50"
        />
        <StatCard 
          icon={<PiggyBank className="text-amber-600" />} 
          title="Total Deposits" 
          value={`৳${stats.totalDeposits}`} 
          color="bg-amber-50"
        />
        <StatCard 
          icon={<Receipt className="text-rose-600" />} 
          title="Meal Rate" 
          value={`৳${stats.mealRate.toFixed(2)}`} 
          color="bg-rose-50"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
          <h3 className="font-semibold text-gray-800 mb-6">Recent Bazaar Trend (Daily)</h3>
          <div className="h-[300px]">
            {stats.chartData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={stats.chartData}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} />
                  <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} />
                  <Tooltip 
                    cursor={{fill: '#f8fafc'}} 
                    contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)'}}
                  />
                  <Bar dataKey="amount" fill="#4f46e5" radius={[4, 4, 0, 0]} barSize={40} />
                </BarChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex items-center justify-center text-gray-400">
                No entry data for chart
              </div>
            )}
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
          <h3 className="font-semibold text-gray-800 mb-4">Quick Actions</h3>
          <div className="space-y-3">
            <ActionButton 
              label="Add Daily Entry" 
              onClick={() => onTabChange('entries')} 
              bgColor="bg-indigo-600 hover:bg-indigo-700" 
            />
            <ActionButton 
              label="Collect Deposit" 
              onClick={() => onTabChange('deposits')} 
              bgColor="bg-emerald-600 hover:bg-emerald-700" 
            />
            <ActionButton 
              label="View Reports" 
              onClick={() => onTabChange('reports')} 
              bgColor="bg-gray-800 hover:bg-gray-900" 
            />
          </div>

          <div className="mt-8 p-4 bg-gray-50 rounded-xl">
             <h4 className="text-xs font-bold uppercase text-gray-400 mb-2">Notice Board</h4>
             <p className="text-sm text-gray-600 italic">"Please ensure all meal counts are submitted before 10 PM each night."</p>
          </div>
        </div>
      </div>
    </div>
  );
};

const StatCard: React.FC<{ icon: React.ReactNode, title: string, value: string, color: string }> = ({ icon, title, value, color }) => (
  <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100 flex items-center gap-4">
    <div className={`w-12 h-12 ${color} rounded-xl flex items-center justify-center`}>
      {icon}
    </div>
    <div>
      <p className="text-sm text-gray-500 font-medium">{title}</p>
      <p className="text-xl font-bold text-gray-900">{value}</p>
    </div>
  </div>
);

const ActionButton: React.FC<{ label: string, onClick: () => void, bgColor: string }> = ({ label, onClick, bgColor }) => (
  <button 
    onClick={onClick}
    className={`w-full py-3 rounded-xl text-white font-medium shadow-sm transition-all ${bgColor}`}
  >
    {label}
  </button>
);

export default Dashboard;

import React, { useState } from 'react';
import { AppState, Member } from '../types';
import { Plus, Trash2, Edit2, UserPlus, Phone } from 'lucide-react';

interface Props {
  state: AppState;
  updateState: (updater: (prev: AppState) => AppState) => void;
}

const MemberTab: React.FC<Props> = ({ state, updateState }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [formData, setFormData] = useState({ name: '', phone: '' });

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (state.members.length >= 8) {
      alert("Maximum 8 members allowed.");
      return;
    }
    if (!formData.name) return;

    const newMember: Member = {
      id: crypto.randomUUID(),
      name: formData.name,
      phone: formData.phone,
      joinDate: new Date().toISOString()
    };

    updateState(prev => ({
      ...prev,
      members: [...prev.members, newMember]
    }));
    setFormData({ name: '', phone: '' });
    setIsAdding(false);
  };

  const removeMember = (id: string) => {
    if (confirm("Are you sure you want to remove this member? This might affect historical data.")) {
      updateState(prev => ({
        ...prev,
        members: prev.members.filter(m => m.id !== id)
      }));
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <header className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Members</h1>
          <p className="text-gray-500">Manage your 8-member mess roster</p>
        </div>
        <button 
          disabled={state.members.length >= 8}
          onClick={() => setIsAdding(!isAdding)}
          className={`flex items-center gap-2 px-4 py-2 rounded-xl font-medium transition-all ${
            isAdding 
              ? 'bg-gray-100 text-gray-600' 
              : 'bg-indigo-600 text-white shadow-lg shadow-indigo-200 hover:bg-indigo-700'
          } disabled:opacity-50 disabled:cursor-not-allowed`}
        >
          {isAdding ? 'Cancel' : <><UserPlus size={18} /> Add Member</>}
        </button>
      </header>

      {isAdding && (
        <form onSubmit={handleAdd} className="bg-white p-6 rounded-2xl shadow-sm border border-gray-200 animate-in fade-in slide-in-from-top-4 duration-300">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Full Name</label>
              <input 
                type="text" 
                required
                value={formData.name}
                onChange={e => setFormData({ ...formData, name: e.target.value })}
                className="w-full px-4 py-2 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none"
                placeholder="John Doe"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Phone (Optional)</label>
              <input 
                type="tel" 
                value={formData.phone}
                onChange={e => setFormData({ ...formData, phone: e.target.value })}
                className="w-full px-4 py-2 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none"
                placeholder="017xxxxxxxx"
              />
            </div>
          </div>
          <button 
            type="submit"
            className="mt-4 w-full sm:w-auto bg-indigo-600 text-white px-6 py-2 rounded-xl font-medium hover:bg-indigo-700"
          >
            Save Member
          </button>
        </form>
      )}

      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        {state.members.map((member, idx) => (
          <div key={member.id} className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100 flex items-center justify-between group hover:border-indigo-100 transition-all">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-gray-100 rounded-full flex items-center justify-center text-gray-500 font-bold text-lg">
                {idx + 1}
              </div>
              <div>
                <h3 className="font-semibold text-gray-900">{member.name}</h3>
                <div className="flex items-center gap-1 text-sm text-gray-400">
                  <Phone size={12} />
                  <span>{member.phone || 'No phone'}</span>
                </div>
              </div>
            </div>
            <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
              <button 
                onClick={() => removeMember(member.id)}
                className="p-2 text-rose-400 hover:text-rose-600 hover:bg-rose-50 rounded-lg"
              >
                <Trash2 size={18} />
              </button>
            </div>
          </div>
        ))}

        {state.members.length === 0 && (
          <div className="col-span-full py-12 text-center text-gray-400 bg-white rounded-2xl border border-dashed border-gray-200">
            No members added yet. Add up to 8 members.
          </div>
        )}
      </div>
    </div>
  );
};

export default MemberTab;

import React, { useState } from 'react';
import { AppState, DailyEntry, MealCounts } from '../types';
import { Calendar, ChevronLeft, ChevronRight, Check, X, Save } from 'lucide-react';

interface Props {
  state: AppState;
  updateState: (updater: (prev: AppState) => AppState) => void;
}

const EntryTab: React.FC<Props> = ({ state, updateState }) => {
  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().slice(0, 10));

  const currentEntry: DailyEntry = state.dailyEntries[selectedDate] || {
    date: selectedDate,
    bazaarAmount: 0,
    bazaarDescription: '',
    meals: {}
  };

  const handleMealToggle = (memberId: string, mealType: keyof MealCounts) => {
    updateState(prev => {
      const entries = { ...prev.dailyEntries };
      const entry = entries[selectedDate] || { date: selectedDate, bazaarAmount: 0, bazaarDescription: '', meals: {} };
      const memberMeals = entry.meals[memberId] || { breakfast: 0, lunch: 0, dinner: 0 };

      const newMeals = { ...memberMeals, [mealType]: memberMeals[mealType] ? 0 : 1 };

      return {
        ...prev,
        dailyEntries: {
          ...entries,
          [selectedDate]: {
            ...entry,
            meals: {
              ...entry.meals,
              [memberId]: newMeals
            }
          }
        }
      };
    });
  };

  const handleBazaarChange = (field: 'amount' | 'desc', value: any) => {
    updateState(prev => {
      const entries = { ...prev.dailyEntries };
      const entry = entries[selectedDate] || { date: selectedDate, bazaarAmount: 0, bazaarDescription: '', meals: {} };

      return {
        ...prev,
        dailyEntries: {
          ...entries,
          [selectedDate]: {
            ...entry,
            [field === 'amount' ? 'bazaarAmount' : 'bazaarDescription']: value
          }
        }
      };
    });
  };

  const moveDate = (days: number) => {
    const d = new Date(selectedDate);
    d.setDate(d.getDate() + days);
    setSelectedDate(d.toISOString().slice(0, 10));
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <header className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Daily Entry</h1>
          <p className="text-gray-500">Update meals and bazaar for specific dates</p>
        </div>
        <div className="flex items-center bg-white p-1 rounded-xl shadow-sm border border-gray-200">
          <button onClick={() => moveDate(-1)} className="p-2 hover:bg-gray-50 rounded-lg"><ChevronLeft size={20} /></button>
          <input 
            type="date" 
            value={selectedDate}
            onChange={e => setSelectedDate(e.target.value)}
            className="px-2 py-1 outline-none text-sm font-semibold bg-transparent"
          />
          <button onClick={() => moveDate(1)} className="p-2 hover:bg-gray-50 rounded-lg"><ChevronRight size={20} /></button>
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Bazaar Section */}
        <section className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
          <h2 className="text-lg font-bold text-gray-900 mb-4 flex items-center gap-2">
            <div className="w-8 h-8 bg-emerald-50 rounded-lg flex items-center justify-center text-emerald-600">
              ৳
            </div>
            Bazaar Cost
          </h2>
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Amount (TK)</label>
              <input 
                type="number"
                value={currentEntry.bazaarAmount || ''}
                onChange={e => handleBazaarChange('amount', parseFloat(e.target.value) || 0)}
                className="w-full px-4 py-3 bg-gray-50 border-none rounded-xl text-lg font-bold text-emerald-700 focus:ring-2 focus:ring-emerald-500 outline-none"
                placeholder="0.00"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Description</label>
              <textarea 
                value={currentEntry.bazaarDescription}
                onChange={e => handleBazaarChange('desc', e.target.value)}
                rows={3}
                className="w-full px-4 py-2 bg-gray-50 border-none rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none resize-none"
                placeholder="Fish, vegetables, etc."
              />
            </div>
          </div>
        </section>

        {/* Meals Section */}
        <section className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
          <h2 className="text-lg font-bold text-gray-900 mb-4 flex items-center gap-2">
            <div className="w-8 h-8 bg-indigo-50 rounded-lg flex items-center justify-center text-indigo-600">
              <Calendar size={18} />
            </div>
            Meal Tracking
          </h2>

          <div className="space-y-4">
            {state.members.length === 0 ? (
              <p className="text-center py-8 text-gray-400">No members to show. Add members first.</p>
            ) : (
              state.members.map(member => {
                const meals = currentEntry.meals[member.id] || { breakfast: 0, lunch: 0, dinner: 0 };
                return (
                  <div key={member.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-xl">
                    <span className="font-medium text-gray-800 text-sm truncate max-w-[100px]">{member.name}</span>
                    <div className="flex gap-2">
                      <MealToggle 
                        label="B" 
                        active={!!meals.breakfast} 
                        onClick={() => handleMealToggle(member.id, 'breakfast')} 
                      />
                      <MealToggle 
                        label="L" 
                        active={!!meals.lunch} 
                        onClick={() => handleMealToggle(member.id, 'lunch')} 
                      />
                      <MealToggle 
                        label="D" 
                        active={!!meals.dinner} 
                        onClick={() => handleMealToggle(member.id, 'dinner')} 
                      />
                    </div>
                  </div>
                );
              })
            )}
          </div>
        </section>
      </div>

      <div className="p-4 bg-indigo-50 border border-indigo-100 rounded-2xl text-indigo-700 text-sm flex items-center gap-3">
        <div className="bg-white p-2 rounded-lg"><Save size={16} /></div>
        <p>Changes are saved automatically as you edit.</p>
      </div>
    </div>
  );
};

