            <tbody className="divide-y divide-gray-50">
              {stats.memberRows.map(row => (
                <tr key={row.id} className="hover:bg-gray-50/50 transition-colors">
                  <td className="px-6 py-4 font-semibold text-gray-900">{row.name}</td>
                  <td className="px-6 py-4 text-gray-600">{row.meals}</td>
                  <td className="px-6 py-4 text-gray-600">৳{row.cost.toFixed(2)}</td>
                  <td className="px-6 py-4 text-indigo-600 font-medium">৳{row.deposit.toFixed(2)}</td>
                  <td className="px-6 py-4">
                    <span className={`px-3 py-1 rounded-full text-sm font-bold ${
                      row.balance >= 0 
                        ? 'bg-emerald-50 text-emerald-600' 
                        : 'bg-rose-50 text-rose-600'
                    }`}>
                      {row.balance >= 0 ? '+' : ''}{row.balance.toFixed(2)}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="bg-emerald-50 p-6 rounded-2xl border border-emerald-100">
          <h3 className="text-emerald-800 font-bold mb-2 flex items-center gap-2">
            <TrendingUp size={18} /> Financial Health
          </h3>
          <p className="text-emerald-700 text-sm">
            Total marketing cost including other expenses is ৳{(stats.totalBazaar + state.otherExpenses).toFixed(2)}. 
            Total deposits collected are ৳{state.deposits.reduce((a, b) => a + b.amount, 0).toFixed(2)}. 
            The mess is currently {
              (state.deposits.reduce((a, b) => a + b.amount, 0) >= (stats.totalBazaar + state.otherExpenses))
                ? 'in surplus'
                : 'short'
            } of funds.
          </p>
        </div>
        <div className="bg-amber-50 p-6 rounded-2xl border border-amber-100">
           <h3 className="text-amber-800 font-bold mb-2 flex items-center gap-2">
            <AlertCircle size={18} /> Quick Report Info
          </h3>
          <ul className="text-amber-700 text-sm space-y-1 list-disc list-inside">
            <li>Meal Rate is calculated across all members.</li>
            <li>Balances indicate who needs to pay more or receive a refund.</li>
            <li>Ensure all daily bazaar records are up to date for accuracy.</li>
          </ul>
        </div>
      </div>
    </div>
  );
};

export default ReportTab;
